// Client-facing filter: keep a meeting only if at least one participant is outside TN.
const INTERNAL_DOMAINS=['tecknuovo.com']; // TN internal email domain(s) — confirm/extend if TN uses others
const p=$json.participants||{};
const ppl=[];if(p.organizer)ppl.push(p.organizer);(p.attendees||[]).forEach(a=>ppl.push(a));
const upns=ppl.map(a=>((a&&a.upn)||'').toLowerCase()).filter(Boolean);
const externals=upns.filter(u=>{const d=u.split('@')[1]||'';return d&&!INTERNAL_DOMAINS.includes(d);});
const external_domains=[...new Set(externals.map(u=>u.split('@')[1]))];
const attendee_check=upns.length?'ok':'unavailable';
// Fail-open: if Graph gave no participant data, keep the call (the watchlist is the primary control) but flag it.
const is_external=attendee_check==='ok'?externals.length>0:true;
return { json: { is_external, external_domains, attendee_check, subject: $json.subject||'' } };

function vttToText(v){
  if(!v) return '';
  const turns=[]; let cur=null; let inCue=false;
  for(const raw of String(v).split(/\r?\n/)){
    const l=raw.trim();
    if(!l){ inCue=false; continue; }
    if(/-->/.test(l)){ inCue=true; continue; }   // timestamp: cue payload follows
    if(!inCue) continue;                          // WEBVTT header / cue id / NOTE -> skip
    const m=l.match(/^<v\s+([^>]+)>([\s\S]*)$/i);
    if(m){
      const speaker=m[1].trim();
      const text=m[2].replace(/<\/v>/ig,'').replace(/<[^>]+>/g,'').trim();
      if(cur && cur.speaker===speaker){ cur.text += ' ' + text; }
      else { cur={speaker,text}; turns.push(cur); }
    } else {
      const text=l.replace(/<[^>]+>/g,'').trim();
      if(!text) continue;
      if(cur){ cur.text += ' ' + text; } else { cur={speaker:'',text}; turns.push(cur); }
    }
  }
  return turns.map(t => (t.speaker?t.speaker+': ':'')+t.text.replace(/\s+/g,' ').trim()).filter(Boolean).join('\n');
}
const e = s => String(s==null?'':s).replace(/'/g,"''");
const tid     = ($('Each transcript').item.json.id) || '';
const subject = ($('Get meeting subject').item.json.subject) || '';
const text    = vttToText($('Get transcript content').item.json.data || $('Get transcript content').item.json.body || '');
const ac  = $('Attendee check').item.json;
const ext = JSON.stringify(ac.external_domains||[]);
const sql =
  "INSERT INTO inbox (source, dedup_key, payload, status) " +
  "SELECT 'teams', '" + e(tid) + "', jsonb_build_object(" +
    "'account', COALESCE((SELECT name FROM accounts WHERE '" + e(subject) + "' ILIKE '%'||name||'%' ORDER BY length(name) DESC LIMIT 1), (SELECT name FROM client_directory WHERE '" + e(subject) + "' ILIKE '%'||name||'%' ORDER BY length(name) DESC LIMIT 1), 'UNKNOWN')," +
    "'title', '" + e(subject) + "'," +
    "'external_domains', '" + e(ext) + "'::jsonb," +
    "'attendee_check', '" + e(ac.attendee_check||'') + "'," +
    "'dedup_key', '" + e(tid) + "'," +
    "'transcript', '" + e(text) + "'" +
  "), 'pending' " +
  "WHERE '" + e(text) + "' <> '' " +
  "ON CONFLICT (dedup_key) DO NOTHING RETURNING id;";
return { json: { sql, transcript_id: tid, subject, chars: text.length } };
